import{_ as t,a as r,h as e,o}from"./chunks/framework.BMvZeQKH.js";const u=JSON.parse('{"title":"快速入门","description":"","frontmatter":{"outline":"deep","title":"快速入门"},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md","lastUpdated":1773588811000}'),i={name:"introduction.md"};function n(l,a,d,h,s,c){return o(),r("div",null,a[0]||(a[0]=[e(`<h1 id="快速入门" tabindex="-1">快速入门 <a class="header-anchor" href="#快速入门" aria-label="Permalink to &quot;快速入门&quot;">​</a></h1><p>欢迎来到字源形码！这是一款入门简单且性能强大的形码输入法。</p><h2 id="🎯-为什么选择字源形码" tabindex="-1">🎯 为什么选择字源形码？ <a class="header-anchor" href="#🎯-为什么选择字源形码" aria-label="Permalink to &quot;🎯 为什么选择字源形码？&quot;">​</a></h2><h3 id="简单易学" tabindex="-1">简单易学 <a class="header-anchor" href="#简单易学" aria-label="Permalink to &quot;简单易学&quot;">​</a></h3><ul><li><strong>仅 20 个核心字根</strong> - 相比五笔的 130+ 字根，大幅降低学习门槛</li><li><strong>30 分钟上手</strong> - 新手也能快速掌握字根编码</li><li><strong>符合直觉</strong> - 字根设计直观，易于记忆</li></ul><h3 id="高效输入" tabindex="-1">高效输入 <a class="header-anchor" href="#高效输入" aria-label="Permalink to &quot;高效输入&quot;">​</a></h3><ul><li><strong>四码定长</strong> - 最多输入 4 个字母</li><li><strong>低重码率</strong> - 打字流畅，无需频繁选词</li><li><strong>科学拆字</strong> - 基于汉字字源和结构，符合自然规律</li></ul><h3 id="适用广泛" tabindex="-1">适用广泛 <a class="header-anchor" href="#适用广泛" aria-label="Permalink to &quot;适用广泛&quot;">​</a></h3><ul><li>日常办公、专业写作、编程开发</li><li>Windows、macOS、Linux 全平台支持</li></ul><h2 id="🚀-快速开始" tabindex="-1">🚀 快速开始 <a class="header-anchor" href="#🚀-快速开始" aria-label="Permalink to &quot;🚀 快速开始&quot;">​</a></h2><h3 id="第一步-了解字根" tabindex="-1">第一步：了解字根 <a class="header-anchor" href="#第一步-了解字根" aria-label="Permalink to &quot;第一步：了解字根&quot;">​</a></h3><p>字源形码基于 20 个核心字根，分布在键盘的各个键位上：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q W E R T Y U I O P</span></span>
<span class="line"><span> A S D F G H J K L</span></span>
<span class="line"><span>  Z X C V B N M</span></span></code></pre></div><p>每个键位对应 1-2 个字根，字形相似的字根会安排在相近的键位。</p><h3 id="第二步-学习编码" tabindex="-1">第二步：学习编码 <a class="header-anchor" href="#第二步-学习编码" aria-label="Permalink to &quot;第二步：学习编码&quot;">​</a></h3><p>字源形码的编码规则：</p><ul><li><strong>一码字</strong>：常用字一键输入（如：我、人、的）</li><li><strong>二码字</strong>：大部分常用字两键输入</li><li><strong>三码字</strong>：大部分字三键输入</li><li><strong>四码字</strong>：复杂字四键输入</li></ul><h3 id="第三步-开始练习" tabindex="-1">第三步：开始练习 <a class="header-anchor" href="#第三步-开始练习" aria-label="Permalink to &quot;第三步：开始练习&quot;">​</a></h3><p><a href="/practice/modern">开始顺序练习 →</a></p><h2 id="📖-学习建议" tabindex="-1">📖 学习建议 <a class="header-anchor" href="#📖-学习建议" aria-label="Permalink to &quot;📖 学习建议&quot;">​</a></h2><h3 id="新手路径" tabindex="-1">新手路径 <a class="header-anchor" href="#新手路径" aria-label="Permalink to &quot;新手路径&quot;">​</a></h3><ol><li><strong>Day 1</strong>：完成顺序练习，熟悉所有字根（约 30-60 分钟）</li><li><strong>Day 2-3</strong>：随机练习巩固记忆（每天 20-30 分钟）</li><li><strong>Week 1-2</strong>：常用字根专项练习</li><li><strong>持续</strong>：在日常生活中使用，形成肌肉记忆</li></ol><h3 id="学习技巧" tabindex="-1">学习技巧 <a class="header-anchor" href="#学习技巧" aria-label="Permalink to &quot;学习技巧&quot;">​</a></h3><ul><li><strong>理解记忆</strong>：理解字根与汉字的关系，不要死记硬背</li><li><strong>多次重复</strong>：短时多次比长时间一次更有效</li><li><strong>实际应用</strong>：尽快在真实场景中使用</li><li><strong>错题复习</strong>：重点练习错误字根</li></ul><h3 id="时间安排" tabindex="-1">时间安排 <a class="header-anchor" href="#时间安排" aria-label="Permalink to &quot;时间安排&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>时间</th><th>目标</th></tr></thead><tbody><tr><td>入门期</td><td>1-3 天</td><td>掌握 20 个字根</td></tr><tr><td>练习期</td><td>1-2 周</td><td>正确率达到 80%</td></tr><tr><td>进阶期</td><td>持续</td><td>速度达到 60 字/分钟</td></tr></tbody></table><h2 id="🎓-练习模式" tabindex="-1">🎓 练习模式 <a class="header-anchor" href="#🎓-练习模式" aria-label="Permalink to &quot;🎓 练习模式&quot;">​</a></h2><p>我们提供了多种练习模式，帮助你循序渐进地学习：</p><table tabindex="0"><thead><tr><th>练习模式</th><th>说明</th><th>推荐阶段</th></tr></thead><tbody><tr><td><a href="/practice/modern">顺序练习</a></td><td>按顺序学习所有字根</td><td>入门期 ✅</td></tr><tr><td><a href="/practice/random">随机练习</a></td><td>随机抽测字根</td><td>练习期 ✅</td></tr><tr><td><a href="/practice/top500">常用字根</a></td><td>专项练习高频字根</td><td>进阶期 ✅</td></tr><tr><td><a href="/practice/error">错题本</a></td><td>练习错误字根</td><td>持续 ✅</td></tr></tbody></table><h2 id="❓-常见问题" tabindex="-1">❓ 常见问题 <a class="header-anchor" href="#❓-常见问题" aria-label="Permalink to &quot;❓ 常见问题&quot;">​</a></h2><h3 id="q-多久能学会" tabindex="-1">Q：多久能学会？ <a class="header-anchor" href="#q-多久能学会" aria-label="Permalink to &quot;Q：多久能学会？&quot;">​</a></h3><p><strong>A</strong>：一般 30 分钟可以掌握 20 个字根，1-2 周内可以熟练使用。</p><h3 id="q-和五笔相比有什么优势" tabindex="-1">Q：和五笔相比有什么优势？ <a class="header-anchor" href="#q-和五笔相比有什么优势" aria-label="Permalink to &quot;Q：和五笔相比有什么优势？&quot;">​</a></h3><p><strong>A</strong>：字根更少（20个 vs 130+），学习曲线更平缓，上手更快。</p><h3 id="q-打字速度能达到多少" tabindex="-1">Q：打字速度能达到多少？ <a class="header-anchor" href="#q-打字速度能达到多少" aria-label="Permalink to &quot;Q：打字速度能达到多少？&quot;">​</a></h3><p><strong>A</strong>：经过 1-2 周练习，大多数用户可以达到每分钟 60 字以上。</p><h3 id="q-适合零基础新手吗" tabindex="-1">Q：适合零基础新手吗？ <a class="header-anchor" href="#q-适合零基础新手吗" aria-label="Permalink to &quot;Q：适合零基础新手吗？&quot;">​</a></h3><p><strong>A</strong>：非常适合！字源形码专为降低学习门槛而设计，新手也能快速上手。</p><h2 id="🔧-下载安装" tabindex="-1">🔧 下载安装 <a class="header-anchor" href="#🔧-下载安装" aria-label="Permalink to &quot;🔧 下载安装&quot;">​</a></h2><p><a href="http://ziyuan.ysepan.com/" target="_blank" rel="noreferrer">字源安装包下载</a></p><p>支持 Windows、macOS、Linux 等平台。</p><h2 id="🤝-社区支持" tabindex="-1">🤝 社区支持 <a class="header-anchor" href="#🤝-社区支持" aria-label="Permalink to &quot;🤝 社区支持&quot;">​</a></h2><ul><li><strong>QQ 群</strong>：点击页面右上角 QQ 图标加入</li><li><strong>官方网站</strong>：<a href="http://ziyuan.ysepan.com/" target="_blank" rel="noreferrer">http://ziyuan.ysepan.com/</a></li></ul><h2 id="💡-立即开始" tabindex="-1">💡 立即开始 <a class="header-anchor" href="#💡-立即开始" aria-label="Permalink to &quot;💡 立即开始&quot;">​</a></h2><p>准备好开始学习了吗？</p><p><a href="/practice/modern">开始顺序练习 →</a></p><hr><p>祝您学习愉快，打字效率节节高升！</p>`,48)]))}const b=t(i,[["render",n]]);export{u as __pageData,b as default};
